 12→// AgentProfile configures model and effort level for a teammate.
 13→type AgentProfile struct {
 14→	Model  string `yaml:"model,omitempty"`
 15→	Effort string `yaml:"effort,omitempty"`
 16→}
 17→
 18→// Config represents the workspace.yaml configuration.
 19→type Config struct {
 20→	RepoURL       string                  `yaml:"repo_url"`
 21→	ProjectPath   string                  `yaml:"project_path"`
 22→	DefaultBranch string                  `yaml:"default_branch"`
 23→	ExtraROMounts []string                `yaml:"extra_ro_mounts"`
 24→	ExtraRWMounts []string                `yaml:"extra_rw_mounts"`
 25→	AgentEnv      map[string]string       `yaml:"agent_env"`
 26→	AgentProfiles map[string]AgentProfile `yaml:"agent_profiles"`
 27→}
 28→
 29→// Workspace represents a loaded workspace with its config and directory.
 30→type Workspace struct {
 31→	Config Config
 32→	Dir    string // absolute path to the workspace directory (e.g. ~/.agentsea/workspaces/<project>/)
 33→}
 34→
 35→// BaseDir returns the root directory for all workspaces (~/.agentsea/workspaces/).
 36→func BaseDir() string {
 37→	return filepath.Join(os.Getenv("HOME"), ".agentsea", "workspaces")
 38→}
 39→
 40→// Load reads workspace.yaml from the given directory and returns a Workspace.
 41→func Load(dir string) (*Workspace, error) {
 42→	absDir, err := filepath.Abs(dir)
 43→	if err != nil {
 44→		return nil, fmt.Errorf("resolving workspace dir: %w", err)
 45→	}
 46→
 47→	data, err := os.ReadFile(filepath.Join(absDir, "workspace.yaml"))
 48→	if err != nil {
 49→		return nil, fmt.Errorf("reading workspace.yaml: %w", err)
 50→	}
 51→
 52→	var cfg Config
 53→	if err := yaml.Unmarshal(data, &cfg); err != nil {
 54→		return nil, fmt.Errorf("parsing workspace.yaml: %w", err)
 55→	}
 56→
 57→	return &Workspace{Config: cfg, Dir: absDir}, nil
 58→}
 59→
 60→// Detect finds the workspace whose project_path matches the current working directory.
 61→// It scans all workspaces in BaseDir() and returns the first match.
 62→func Detect() (*Workspace, error) {
 63→	return DetectWithBase(BaseDir())
 64→}
 65→
 66→// DetectWithBase is like Detect but uses a custom base directory (for testing).
 67→func DetectWithBase(baseDir string) (*Workspace, error) {
 68→	cwd, err := os.Getwd()
 69→	if err != nil {
 70→		return nil, fmt.Errorf("getting cwd: %w", err)
 71→	}
 72→
 73→	entries, err := os.ReadDir(baseDir)
 74→	if err != nil {
 75→		return nil, fmt.Errorf("reading workspaces dir: %w", err)
 76→	}
 77→
 78→	for _, entry := range entries {
 79→		if !entry.IsDir() {
 80→			continue
 81→		}
 82→		wsDir := filepath.Join(baseDir, entry.Name())
 83→		ws, err := Load(wsDir)
 84→		if err != nil {
 85→			continue // skip unreadable workspaces
 86→		}
 87→
 88→		projPath := ws.Config.ProjectPath
 89→		if projPath == "" {
 90→			continue
 91→		}
 92→		// Normalize project_path to absolute
 93→		if !filepath.IsAbs(projPath) {
 94→			continue
 95→		}
 96→		// Clean both paths for consistent comparison
 97→		projPath = filepath.Clean(projPath)
 98→		cleanCwd := filepath.Clean(cwd)
 99→
100→		if cleanCwd == projPath || strings.HasPrefix(cleanCwd, projPath+string(filepath.Separator)) {
101→			return ws, nil
102→		}
103→	}
104→
105→	return nil, fmt.Errorf("no workspace found for cwd %s", cwd)
106→}
