108→// AgentRepoPath returns the path to an agent's git repository clone.
109→func (w *Workspace) AgentRepoPath(name string) string {
110→	return filepath.Join(w.Dir, "agents", name, "repo")
111→}
112→
113→// AgentSSHPath returns the path to an agent's SSH key directory.
114→func (w *Workspace) AgentSSHPath(name string) string {
115→	return filepath.Join(w.Dir, "agents", name, "ssh")
116→}
117→
118→// CanonicalPath returns the path to the bare canonical clone.
119→func (w *Workspace) CanonicalPath() string {
120→	return filepath.Join(w.Dir, "canonical")
121→}
