 83→func TestDetect(t *testing.T) {
 84→	// Create a fake base dir with one workspace
 85→	baseDir := t.TempDir()
 86→	wsDir := filepath.Join(baseDir, "myproject")
 87→	if err := os.MkdirAll(wsDir, 0755); err != nil {
 88→		t.Fatal(err)
 89→	}
 90→
 91→	// Create a project directory to match against
 92→	projectDir := t.TempDir()
 93→
 94→	yaml := "repo_url: git@github.com:org/repo.git\nproject_path: " + projectDir + "\ndefault_branch: main\n"
 95→	if err := os.WriteFile(filepath.Join(wsDir, "workspace.yaml"), []byte(yaml), 0644); err != nil {
 96→		t.Fatal(err)
 97→	}
 98→
 99→	// Change to the project directory
100→	origDir, _ := os.Getwd()
101→	defer os.Chdir(origDir)
102→	os.Chdir(projectDir)
103→
104→	ws, err := DetectWithBase(baseDir)
105→	if err != nil {
106→		t.Fatalf("DetectWithBase() error: %v", err)
107→	}
108→	if ws.Config.ProjectPath != projectDir {
109→		t.Errorf("ProjectPath = %q, want %q", ws.Config.ProjectPath, projectDir)
110→	}
111→}
